package main.rice.obj;

import java.util.List;

/**
 * A representation of Python list objects.
 *
 * @param <InnerType> the type of each element
 */
public class PyListObj<InnerType extends APyObj> extends AIterablePyObj<InnerType> {
    public PyListObj(List<InnerType> value) {
        this.value = value;
    }

    @Override
    public String toString() {
        return this.getValue().toString();
    }

    @Override
    public boolean equals(Object obj) {
        if (!(obj instanceof PyListObj)) {
            return false;
        }
        return super.equals(obj);
    }
}

package main.rice.obj;

/**
 * An abstract class whose instances represent specific Python objects.
 */
public abstract class APyObj {

    /**
     * Returns the underlying Java representation of this Python object.
     *
     * @return the underlying value
     */
    public abstract Object getValue();

    @Override
    public abstract String toString();

    @Override
    public boolean equals(Object obj) {
        if (!(obj instanceof APyObj other)) {
            return false;
        }
        return this.getValue().equals(other.getValue());
    }

    @Override
    public int hashCode() {
        return this.getValue().hashCode();
    }
}

