package main.rice.obj;

import java.util.ArrayList;
import java.util.List;

/**
 * A representation of Python string objects.
 */
public class PyStringObj extends AIterablePyObj<PyCharObj> {
    public PyStringObj(String value) {
        this.value = new ArrayList<>();
        for (int idx = 0; idx < value.length(); idx++) {
            this.value.add(new PyCharObj(value.charAt(idx)));
        }
    }

    public PyStringObj(List<PyCharObj> value) {
        this.value = value;
    }

    @Override
    public String toString() {
        StringBuilder sb = new StringBuilder();
        for (PyCharObj character : this.value) {
            sb.append(character.getValue());
        }
        return "'" + sb + "'";
    }

    @Override
    public boolean equals(Object obj) {
        if (!(obj instanceof PyStringObj)) {
            return false;
        }
        return super.equals(obj);
    }
}

package main.rice.obj;

import java.util.Set;

/**
 * A representation of Python set objects.
 *
 * @param <InnerType> the type of each element
 */
public class PySetObj<InnerType extends APyObj> extends AIterablePyObj<InnerType> {
    public PySetObj(Set<InnerType> value) {
        this.value = value;
    }

    @Override
    public String toString() {
        if (this.value.size() == 0) {
            return "set()";
        }
        String repr = this.value.toString();
        return "{" + repr.substring(1, repr.length() - 1) + "}";
    }

    @Override
    public boolean equals(Object obj) {
        if (!(obj instanceof PySetObj)) {
            return false;
        }
        return super.equals(obj);
    }
}

package main.rice.obj;

import java.util.List;

/**
 * A representation of Python tuple objects.
 *
 * @param <InnerType> the type of each element
 */
public class PyTupleObj<InnerType extends APyObj> extends AIterablePyObj<InnerType> {
    public PyTupleObj(List<InnerType> value) {
        this.value = value;
    }

    @Override
    public String toString() {
        StringBuilder repr = new StringBuilder("(");
        for (InnerType elem : this.value) {
            repr.append(elem).append(", ");
        }
        if (this.value.size() > 1) {
            repr = new StringBuilder(repr.substring(0, repr.length() - 2));
        } else if (this.value.size() == 1) {
            repr = new StringBuilder(repr.substring(0, repr.length() - 1));
        }
        repr.append(")");
        return repr.toString();
    }

    @Override
    public boolean equals(Object obj) {
        if (!(obj instanceof PyTupleObj)) {
            return false;
        }
        return super.equals(obj);
    }
}

