package main.rice.obj;

/**
 * A representation of Python int objects.
 */
public class PyIntObj extends APyObj {
    private final Integer value;

    public PyIntObj(Integer value) {
        this.value = value;
    }

    @Override
    public Integer getValue() {
        return this.value;
