import java.util.ArrayList;
import java.util.LinkedHashSet;
import java.util.List;
import java.util.Random;
import java.util.Set;

/**
 * A node for generating Python list values.
 *
 * @param <InnerType> the list element type
 */
public class PyListNode<InnerType extends APyObj>
        extends AIterablePyNode<PyListObj<InnerType>, InnerType> {
    private static final Random RNG = new Random();

    public PyListNode(APyNode<InnerType> leftChild) {
        super(leftChild);
    }

    @Override
    public Set<PyListObj<InnerType>> genExVals() {
        return genValsForLengths(this.exDomain, this.leftChild.genExVals());
    }

    @Override
    public PyListObj<InnerType> genRandVal() {
        if (this.ranDomain.isEmpty()) {
            throw new IllegalStateException("random domain must be non-empty");
        }
        int len = this.ranDomain.get(RNG.nextInt(this.ranDomain.size()));
        List<InnerType> values = new ArrayList<>();
        for (int idx = 0; idx < len; idx++) {
            values.add(this.leftChild.genRandVal());
        }
        return new PyListObj<>(values);
    }

    @Override
    protected Set<PyListObj<InnerType>> genRandVals() {
        return genValsForLengths(this.ranDomain, this.leftChild.genRandVals());
    }

    private Set<PyListObj<InnerType>> genValsForLengths(List<Integer> lengths,
                                                        Set<InnerType> childVals) {
        Set<PyListObj<InnerType>> results = new LinkedHashSet<>();
        for (Integer len : lengths) {
            buildLists(len, childVals.stream().toList(), new ArrayList<>(), results);
        }
        return results;
    }

    private void buildLists(int remaining, List<InnerType> childVals, List<InnerType> current,
                            Set<PyListObj<InnerType>> results) {
        if (remaining == 0) {
            results.add(new PyListObj<>(new ArrayList<>(current)));
            return;
        }
        for (InnerType childVal : childVals) {
            current.add(childVal);
            buildLists(remaining - 1, childVals, current, results);
            current.remove(current.size() - 1);
        }
    }
}

