/**
 * A node for generating Python string values.
 */
public class PyStringNode extends APyNode<PyStringObj> {
    private static final Random RNG = new Random();
    private final String alphabet;

    public PyStringNode(String alphabet) {
        this.alphabet = alphabet;
    }

    @Override
    public Set<PyStringObj> genExVals() {
        return genValsForLengths(this.exDomain);
    }

    @Override
    public PyStringObj genRandVal() {
        if (this.ranDomain.isEmpty()) {
            throw new IllegalStateException("random domain must be non-empty");
        }
        int len = this.ranDomain.get(RNG.nextInt(this.ranDomain.size()));
        StringBuilder sb = new StringBuilder();
        for (int idx = 0; idx < len; idx++) {
            sb.append(this.alphabet.charAt(RNG.nextInt(this.alphabet.length())));
        }
        return new PyStringObj(sb.toString());
    }

    @Override
    protected Set<PyStringObj> genRandVals() {
        return genValsForLengths(this.ranDomain);
    }

    private Set<PyStringObj> genValsForLengths(List<Integer> lengths) {
        Set<PyStringObj> results = new LinkedHashSet<>();
        for (Integer len : lengths) {
            buildStrings(len, new StringBuilder(), results);
        }
        return results;
    }

    private void buildStrings(int remaining, StringBuilder current, Set<PyStringObj> results) {
        if (remaining == 0) {
            results.add(new PyStringObj(current.toString()));
            return;
        }
        for (int idx = 0; idx < this.alphabet.length(); idx++) {
            current.append(this.alphabet.charAt(idx));
            buildStrings(remaining - 1, current, results);
            current.deleteCharAt(current.length() - 1);
        }
    }
}

