package main.rice.basegen;

import main.rice.node.APyNode;
import main.rice.obj.APyObj;
import main.rice.test.TestCase;

import java.util.ArrayList;
import java.util.LinkedHashSet;
import java.util.List;
import java.util.Set;

/**
 * Generates exhaustive and random test cases from node specifications.
 */
public class BaseSetGenerator {
    private final List<APyNode<?>> nodes;
    private final int numRand;

    public BaseSetGenerator(List<APyNode<?>> nodes, int numRand) {
        this.nodes = new ArrayList<>(nodes);
        this.numRand = numRand;
    }

    public Set<TestCase> genExTests() {
        Set<TestCase> results = new LinkedHashSet<>();
        buildExTests(0, new ArrayList<>(), results);
        return results;
    }

    public Set<TestCase> genRandTests(int numTests) {
        Set<TestCase> results = new LinkedHashSet<>();
        int attempts = 0;
        int maxAttempts = Math.max(50, numTests * 20);
        while (results.size() < numTests && attempts < maxAttempts) {
            results.add(new TestCase(genSingleRandomArgs()));
            attempts++;
        }
        return results;
    }

    public List<TestCase> genBaseSet() {
        return genTests(this.numRand);
    }

    public List<TestCase> genTests(int numRand) {
        Set<TestCase> exTests = genExTests();
        List<TestCase> result = new ArrayList<>(exTests);
        Set<TestCase> randTests = genRandTests(numRand);
        for (TestCase testCase : randTests) {
            if (!exTests.contains(testCase)) {
                result.add(testCase);
            }
        }
        return result;
    }

    private void buildExTests(int idx, List<APyObj> current, Set<TestCase> results) {
        if (idx == this.nodes.size()) {
            results.add(new TestCase(current));
            return;
        }
        APyNode<?> node = this.nodes.get(idx);
        for (Object value : node.genExVals()) {
            current.add((APyObj) value);
            buildExTests(idx + 1, current, results);
            current.remove(current.size() - 1);
        }
    }

    private List<APyObj> genSingleRandomArgs() {
        List<APyObj> args = new ArrayList<>();
        for (APyNode<?> node : this.nodes) {
            args.add((APyObj) node.genRandVal());
        }
        return args;
    }
}

package test.rice.node;

import main.rice.basegen.BaseSetGenerator;
import main.rice.node.APyNode;
import main.rice.node.PyDictNode;
import main.rice.node.PyIntNode;
import main.rice.node.PySetNode;
import main.rice.obj.PyDictObj;
import main.rice.obj.PyIntObj;
import main.rice.obj.PySetObj;
import main.rice.test.TestCase;
import org.junit.jupiter.api.Test;

import java.util.Arrays;
import java.util.HashMap;
import java.util.HashSet;
import java.util.List;
import java.util.Set;

import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.junit.jupiter.api.Assertions.assertTrue;

class PyNodeEdgeCaseTest {

    private static PyIntNode createIntNode(List<Integer> exDomain, List<Integer> ranDomain) {
        PyIntNode node = new PyIntNode();
        node.setExDomain(exDomain);
        node.setRanDomain(ranDomain);
        return node;
    }

    @Test
    void testSetExhaustiveDoesNotCreateDuplicateElements() {
        PyIntNode intNode = createIntNode(Arrays.asList(1, 2, 3), Arrays.asList(1, 2, 3));
        PySetNode<PyIntObj> setNode = new PySetNode<>(intNode);
        setNode.setExDomain(Arrays.asList(2));

        Set<PySetObj<PyIntObj>> result = setNode.genExVals();

        assertEquals(3, result.size());
        assertTrue(result.contains(new PySetObj<>(new HashSet<>(Arrays.asList(
                new PyIntObj(1), new PyIntObj(2))))));
        assertTrue(result.contains(new PySetObj<>(new HashSet<>(Arrays.asList(
                new PyIntObj(1), new PyIntObj(3))))));
        assertTrue(result.contains(new PySetObj<>(new HashSet<>(Arrays.asList(
                new PyIntObj(2), new PyIntObj(3))))));
    }

    @Test
    void testDictExhaustiveCombinesDistinctKeysWithAllValueChoices() {
        PyIntNode keyNode = createIntNode(Arrays.asList(1, 2), Arrays.asList(1, 2));
        PyIntNode valNode = createIntNode(Arrays.asList(10, 20), Arrays.asList(10, 20));
        PyDictNode<PyIntObj, PyIntObj> dictNode = new PyDictNode<>(keyNode, valNode);
        dictNode.setExDomain(Arrays.asList(2));

        Set<PyDictObj<PyIntObj, PyIntObj>> result = dictNode.genExVals();

        assertEquals(4, result.size());
        HashMap<PyIntObj, PyIntObj> expected = new HashMap<>();
        expected.put(new PyIntObj(1), new PyIntObj(10));
        expected.put(new PyIntObj(2), new PyIntObj(20));
        assertTrue(result.contains(new PyDictObj<>(expected)));
    }

    @Test
    void testBaseSetGeneratorBuildsCartesianProductForThreeArguments() {
        PyIntNode node1 = createIntNode(Arrays.asList(1, 2), Arrays.asList(1, 2));
        PyIntNode node2 = createIntNode(Arrays.asList(3), Arrays.asList(3));
        PyIntNode node3 = createIntNode(Arrays.asList(4, 5), Arrays.asList(4, 5));
        BaseSetGenerator generator = new BaseSetGenerator(List.of(node1, node2, node3), 0);

        Set<TestCase> result = generator.genExTests();

        assertEquals(4, result.size());
        assertTrue(result.contains(new TestCase(List.of(new PyIntObj(1), new PyIntObj(3), new PyIntObj(4)))));
        assertTrue(result.contains(new TestCase(List.of(new PyIntObj(2), new PyIntObj(3), new PyIntObj(5)))));
    }
