/**
 * A node for generating Python set values.
 *
 * @param <InnerType> the set element type
 */
public class PySetNode<InnerType extends APyObj>
        extends AIterablePyNode<PySetObj<InnerType>, InnerType> {
    private static final Random RNG = new Random();

    public PySetNode(APyNode<InnerType> leftChild) {
        super(leftChild);
    }

    @Override
    public Set<PySetObj<InnerType>> genExVals() {
        return genValsForSizes(this.exDomain, this.leftChild.genExVals());
    }

    @Override
    public PySetObj<InnerType> genRandVal() {
        if (this.ranDomain.isEmpty()) {
            throw new IllegalStateException("random domain must be non-empty");
        }
        List<InnerType> candidates = new ArrayList<>(this.leftChild.genRandVals());
        int size = this.ranDomain.get(RNG.nextInt(this.ranDomain.size()));
        if (size > candidates.size()) {
            throw new IllegalStateException("not enough unique random values to build set");
        }
        Set<InnerType> values = new LinkedHashSet<>();
        while (values.size() < size) {
            values.add(candidates.get(RNG.nextInt(candidates.size())));
        }
        return new PySetObj<>(values);
    }

    @Override
    protected Set<PySetObj<InnerType>> genRandVals() {
        return genValsForSizes(this.ranDomain, this.leftChild.genRandVals());
    }

    private Set<PySetObj<InnerType>> genValsForSizes(List<Integer> sizes, Set<InnerType> childVals) {
        Set<PySetObj<InnerType>> results = new LinkedHashSet<>();
        List<InnerType> candidates = new ArrayList<>(childVals);
        for (Integer size : sizes) {
            buildSets(size, 0, candidates, new LinkedHashSet<>(), results);
        }
        return results;
    }

    private void buildSets(int remaining, int startIdx, List<InnerType> candidates,
                           LinkedHashSet<InnerType> current, Set<PySetObj<InnerType>> results) {
        if (remaining == 0) {
            results.add(new PySetObj<>(new LinkedHashSet<>(current)));
            return;
        }
        for (int idx = startIdx; idx <= candidates.size() - remaining; idx++) {
            current.add(candidates.get(idx));
            buildSets(remaining - 1, idx + 1, candidates, current, results);
            current.remove(candidates.get(idx));
        }
    }
}

