package main.rice.basegen;

import main.rice.node.APyNode;
import main.rice.obj.APyObj;
import main.rice.test.TestCase;

import java.util.ArrayList;
import java.util.LinkedHashSet;
import java.util.List;
import java.util.Set;

/**
 * Generates exhaustive and random test cases from node specifications.
 */
public class BaseSetGenerator {
    private final List<APyNode<?>> nodes;
    private final int numRand;

    public BaseSetGenerator(List<APyNode<?>> nodes, int numRand) {
        this.nodes = new ArrayList<>(nodes);
        this.numRand = numRand;
    }

    public Set<TestCase> genExTests() {
        Set<TestCase> results = new LinkedHashSet<>();
        buildExTests(0, new ArrayList<>(), results);
        return results;
    }

    public Set<TestCase> genRandTests(int numTests) {
        Set<TestCase> results = new LinkedHashSet<>();
        int attempts = 0;
        int maxAttempts = Math.max(50, numTests * 20);
        while (results.size() < numTests && attempts < maxAttempts) {
            results.add(new TestCase(genSingleRandomArgs()));
            attempts++;
        }
        return results;
    }

    public List<TestCase> genBaseSet() {
        return genTests(this.numRand);
    }

    public List<TestCase> genTests(int numRand) {
        Set<TestCase> exTests = genExTests();
        List<TestCase> result = new ArrayList<>(exTests);
        Set<TestCase> randTests = genRandTests(numRand);
        for (TestCase testCase : randTests) {
            if (!exTests.contains(testCase)) {
                result.add(testCase);
            }
        }
        return result;
    }

    private void buildExTests(int idx, List<APyObj> current, Set<TestCase> results) {
        if (idx == this.nodes.size()) {
            results.add(new TestCase(current));
            return;
        }
        APyNode<?> node = this.nodes.get(idx);
        for (Object value : node.genExVals()) {
            current.add((APyObj) value);
            buildExTests(idx + 1, current, results);
            current.remove(current.size() - 1);
        }
    }

    private List<APyObj> genSingleRandomArgs() {
        List<APyObj> args = new ArrayList<>();
        for (APyNode<?> node : this.nodes) {
            args.add((APyObj) node.genRandVal());
        }
        return args;
    }
}

