@@ -0,0 +1,98 @@
+package main.rice.node;
+
+import main.rice.obj.APyObj;
+import main.rice.obj.PyDictObj;
+
+import java.util.ArrayList;
+import java.util.LinkedHashMap;
+import java.util.LinkedHashSet;
+import java.util.List;
+import java.util.Map;
+import java.util.Random;
+import java.util.Set;
+
+/**
+ * A node for generating Python dict values.
+ *
+ * @param <KeyType> key type
+ * @param <ValType> value type
+ */
+public class PyDictNode<KeyType extends APyObj, ValType extends APyObj>
+        extends APyNode<PyDictObj<KeyType, ValType>> {
+    private static final Random RNG = new Random();
+    private final APyNode<KeyType> leftChild;
+    private final APyNode<ValType> rightChild;
+
+    public PyDictNode(APyNode<KeyType> leftChild, APyNode<ValType> rightChild) {
+        this.leftChild = leftChild;
+        this.rightChild = rightChild;
+    }
+
+    public APyNode<KeyType> getLeftChild() {
+        return this.leftChild;
+    }
+
+    public APyNode<ValType> getRightChild() {
+        return this.rightChild;
+    }
+
+    @Override
+    public Set<PyDictObj<KeyType, ValType>> genExVals() {
+        return genValsForSizes(this.exDomain, this.leftChild.genExVals(), this.rightChild.genExVals());
+    }
+
+    @Override
+    public PyDictObj<KeyType, ValType> genRandVal() {
+        if (this.ranDomain.isEmpty()) {
+            throw new IllegalStateException("random domain must be non-empty");
+        }
+        List<KeyType> keys = new ArrayList<>(this.leftChild.genRandVals());
+        List<ValType> vals = new ArrayList<>(this.rightChild.genRandVals());
+        int size = this.ranDomain.get(RNG.nextInt(this.ranDomain.size()));
+        if (size > keys.size()) {
+            throw new IllegalStateException("not enough unique random keys to build dict");
+        }
+        Map<KeyType, ValType> result = new LinkedHashMap<>();
+        List<KeyType> available = new ArrayList<>(keys);
+        while (result.size() < size) {
+            int keyIdx = RNG.nextInt(available.size());
+            KeyType key = available.remove(keyIdx);
+            ValType val = vals.get(RNG.nextInt(vals.size()));
+            result.put(key, val);
+        }
+        return new PyDictObj<>(result);
+    }
+
+    @Override
+    protected Set<PyDictObj<KeyType, ValType>> genRandVals() {
+        return genValsForSizes(this.ranDomain, this.leftChild.genRandVals(), this.rightChild.genRandVals());
+    }
+
+    private Set<PyDictObj<KeyType, ValType>> genValsForSizes(List<Integer> sizes, Set<KeyType> keyVals,
+                                                             Set<ValType> valVals) {
+        Set<PyDictObj<KeyType, ValType>> results = new LinkedHashSet<>();
+        List<KeyType> keys = new ArrayList<>(keyVals);
+        List<ValType> vals = new ArrayList<>(valVals);
+        for (Integer size : sizes) {
+            buildDicts(size, 0, keys, vals, new LinkedHashMap<>(), results);
+        }
+        return results;
+    }
+
+    private void buildDicts(int remaining, int startIdx, List<KeyType> keys, List<ValType> vals,
+                            LinkedHashMap<KeyType, ValType> current,
+                            Set<PyDictObj<KeyType, ValType>> results) {
+        if (remaining == 0) {
+            results.add(new PyDictObj<>(new LinkedHashMap<>(current)));
+            return;
+        }
+        for (int idx = startIdx; idx <= keys.size() - remaining; idx++) {
+            KeyType key = keys.get(idx);
+            for (ValType val : vals) {
+                current.put(key, val);
+                buildDicts(remaining - 1, idx + 1, keys, vals, current, results);
+                current.remove(key);
+            }
+        }
+    }
+}
